export function proofImageClass(kind = "site") {
  return cx(
    ui.proofImage,
    kind === "landing" && "object-top [transform:scale(1.08)] [transform-origin:50%_8%]",
    kind === "dashboard" && "object-left-top [transform:scale(1.32)] [transform-origin:18%_8%]",
  );
}

export function screenshotImageClass(kind = "site", scale: "normal" | "compact" = "normal") {
  return cx(
    "block h-full w-full object-cover object-[center_34%] [filter:saturate(1.05)_contrast(1.04)]",
    kind === "landing" && "object-[center_18%] [transform:scale(1.08)] [transform-origin:50%_12%]",
    kind === "dashboard" && (scale === "compact"
      ? "object-left-top [transform:scale(1.28)] [transform-origin:16%_8%]"
      : "object-left-top [transform:scale(1.3)] [transform-origin:16%_8%]"),
    kind === "diagram" && "object-center [transform:scale(1.02)]",
  );
}
